import {
  useRef,
  useState,
  useCallback,
  useEffect,
  useSyncExternalStore,
  type CSSProperties,
} from "react";
import { useDrag } from "@use-gesture/react";

// ============================================================================
// Constants
// ============================================================================

const DEFAULT_DISMISS_THRESHOLD_PERCENT = 0.3; // 30% of modal height
const DEFAULT_VELOCITY_THRESHOLD = 0.5; // Velocity in px/ms
const DEFAULT_RUBBER_BAND_FACTOR = 0.08; // Resistance factor for upward drag (lower = stronger resistance)

// Animation timing (dismiss matches CSS exit animation: 200ms ease-in)
const SNAP_BACK_TRANSITION = "transform 300ms cubic-bezier(0.32, 0.72, 0, 1)";
const DISMISS_DURATION_MS = 200;
const DISMISS_TRANSITION = `transform ${DISMISS_DURATION_MS}ms ease-in`;

// ============================================================================
// Reduced Motion Detection
// ============================================================================

function getReducedMotionSnapshot(): boolean {
  if (typeof window === "undefined") return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}

function subscribeToReducedMotion(callback: () => void): () => void {
  if (typeof window === "undefined") return () => {};
  const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)");
  mediaQuery.addEventListener("change", callback);
  return () => mediaQuery.removeEventListener("change", callback);
}

function getServerSnapshot(): boolean {
  return false;
}

function useReducedMotion(): boolean {
  return useSyncExternalStore(
    subscribeToReducedMotion,
    getReducedMotionSnapshot,
    getServerSnapshot
  );
}

// ============================================================================
// Types
// ============================================================================

export interface UseDraggableModalOptions {
  /**
   * Whether drag-to-dismiss is enabled
   */
  enabled: boolean;

  /**
   * Whether the modal is open
   */
  open: boolean;

  /**
   * Callback when the modal should be dismissed
   */
  onDismiss: () => void;

  /**
   * Ref to the modal element for measuring height
   */
  modalRef: React.RefObject<HTMLDivElement | null>;

  /**
   * Dismiss threshold as a percentage of modal height (0-1)
   * @default 0.3
   */
  dismissThresholdPercent?: number;

  /**
   * Velocity threshold in px/ms to trigger dismiss
   * @default 0.5
   */
  velocityThreshold?: number;

  /**
   * Resistance factor for rubber band effect when dragging upward (0-1).
   * Lower values = stronger resistance.
   * @default 0.08
   */
  rubberBandFactor?: number;
}

export interface UseDraggableModalReturn {
  /**
   * Props to spread on the draggable element (gesture handlers)
   */
  dragProps: Record<string, unknown>;

  /**
   * Style object to apply to the modal for transform and transition.
   * Includes animation-disabling properties when drag-dismissing.
   */
  style: CSSProperties;

  /**
   * Ref to attach to the scrollable body element for scroll awareness
   */
  bodyRef: React.RefObject<HTMLDivElement | null>;
}

// ============================================================================
// Utility Functions
// ============================================================================

/**
 * Applies rubber band resistance when dragging in the wrong direction (upward)
 */
function applyRubberBand(offset: number, factor: number): number {
  if (offset < 0) {
    return offset * factor;
  }
  return offset;
}

// ============================================================================
// Hook
// ============================================================================

export function useDraggableModal({
  enabled,
  open,
  onDismiss,
  modalRef,
  dismissThresholdPercent = DEFAULT_DISMISS_THRESHOLD_PERCENT,
  velocityThreshold = DEFAULT_VELOCITY_THRESHOLD,
  rubberBandFactor = DEFAULT_RUBBER_BAND_FACTOR,
}: UseDraggableModalOptions): UseDraggableModalReturn {
  const [offsetY, setOffsetY] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const [isDragDismissing, setIsDragDismissing] = useState(false);
  const bodyRef = useRef<HTMLDivElement | null>(null);
  const prefersReducedMotion = useReducedMotion();
  const isDraggingRef = useRef(false);
  const onDismissRef = useRef(onDismiss);
  onDismissRef.current = onDismiss;

  // Reset state when modal opens
  useEffect(() => {
    if (open) {
      setOffsetY(0);
      setIsDragging(false);
      setIsDragDismissing(false);
      isDraggingRef.current = false;
    }
  }, [open]);

  // Safety handler: reset state if gesture library misses the pointer release
  // This happens occasionally, especially when using a mouse
  useEffect(() => {
    if (!enabled) return;

    const handlePointerUp = () => {
      if (isDraggingRef.current) {
        isDraggingRef.current = false;
        setIsDragging(false);
        setOffsetY(0);
      }
    };

    document.addEventListener("pointerup", handlePointerUp);

    return () => {
      document.removeEventListener("pointerup", handlePointerUp);
    };
  }, [enabled]);

  // Check if the gesture target is within a scrollable Modal.Body
  // We don't want to cancel the drag if the target is within a scrollable Modal.Body
  // as this would prevent the user from scrolling the body.
  const shouldCancelDrag = useCallback(
    (event: PointerEvent | MouseEvent | TouchEvent | KeyboardEvent) => {
      const body = bodyRef.current;
      if (!body) return false;

      // Check if body has scrollable content
      const hasScrollableContent = body.scrollHeight > body.clientHeight;
      if (!hasScrollableContent) return false;

      // Check if the event target is within the body
      const target = event.target as Node | null;
      return target !== null && body.contains(target);
    },
    []
  );

  const bind = useDrag(
    ({
      down,
      movement: [, my],
      velocity: [, vy],
      direction: [, dy],
      cancel,
      canceled,
      first,
      last,
      event,
    }) => {
      if (!enabled) {
        return;
      }

      // If the gesture was canceled, reset state
      if (canceled) {
        isDraggingRef.current = false;
        setIsDragging(false);
        setOffsetY(0);
        return;
      }

      // Check if gesture is on scrollable Modal.Body (only on first touch)
      if (first && event && shouldCancelDrag(event)) {
        cancel();
        return;
      }

      // Reset drag dismissing state at the start of a new gesture
      if (first) {
        setIsDragDismissing(false);
      }

      if (down) {
        isDraggingRef.current = true;
        setIsDragging(true);
        // While dragging, apply rubber band effect to constrain upward drag
        setOffsetY(applyRubberBand(my, rubberBandFactor));
      } else if (last) {
        // On release
        isDraggingRef.current = false;
        setIsDragging(false);

        // Calculate dismiss threshold based on modal height
        const modalHeight = modalRef.current?.offsetHeight ?? 0;
        const dismissThreshold = modalHeight * dismissThresholdPercent;

        // Check if we should dismiss based on velocity or distance
        const shouldDismiss =
          (vy > velocityThreshold && dy > 0) || my > dismissThreshold;

        if (shouldDismiss) {
          // Start drag dismiss animation
          setIsDragDismissing(true);
          setOffsetY(modalHeight);

          // Call onDismiss after the animation completes
          setTimeout(() => {
            onDismissRef.current();
          }, DISMISS_DURATION_MS);
        } else {
          // Snap back to original position
          setOffsetY(0);
        }
      }
    },
    {
      axis: "y",
      filterTaps: true,
    }
  );

  const dragProps = bind();

  // Determine which transition to use
  let transition: string;
  if (prefersReducedMotion) {
    transition = "none";
  } else if (isDragging) {
    transition = "none";
  } else if (isDragDismissing) {
    transition = DISMISS_TRANSITION;
  } else {
    transition = SNAP_BACK_TRANSITION;
  }

  const style: CSSProperties = enabled
    ? {
        transform: offsetY !== 0 ? `translateY(${offsetY}px)` : undefined,
        transition,
        // When drag-dismissing, disable the CSS exit animation and use our inline transition
        ...(isDragDismissing && {
          animation: "none",
          animationName: "none",
          animationDuration: "0s",
        }),
      }
    : {};

  return {
    dragProps,
    style,
    bodyRef,
  };
}
