import { forwardRef, type HTMLAttributes, type ReactNode } from "react";
import { clsx } from "clsx";
import { Heading } from "react-aria-components";
import XmarkIcon from "@fortawesome/fontawesome-pro/svgs/regular/xmark.svg";
import { Button } from "../../../Button";
import { textClassNames } from "../../../Text";
import { useTranslations } from "../../../hooks/useTranslations";
import { useModalContext } from "../../ModalContext";
import translations from "./i18n.json";
import * as styles from "./ModalHeader.css";

interface ModalHeaderWithCloseButtonProps {
  /**
   * Whether to show the close button
   */
  showCloseButton: true;

  /**
   * Accessible label for the close button.
   * Defaults to a localized "Close" based on the app's locale.
   */
  closeButtonLabel?: string;
}

interface ModalHeaderWithoutCloseButtonProps {
  /**
   * Whether to show the close button
   * @default false
   */
  showCloseButton?: false;

  closeButtonLabel?: never;
}

interface ModalHeaderBaseProps {
  /**
   * The title of the modal (can be a string or ReactNode)
   */
  children: ReactNode;
}

export type ModalHeaderProps = ModalHeaderBaseProps &
  (ModalHeaderWithCloseButtonProps | ModalHeaderWithoutCloseButtonProps) &
  Omit<HTMLAttributes<HTMLDivElement>, "children">;

export const ModalHeader = forwardRef<HTMLDivElement, ModalHeaderProps>(
  (
    {
      children,
      showCloseButton = false,
      closeButtonLabel,
      className,
      ...props
    },
    ref
  ) => {
    const { onClose } = useModalContext();
    const t = useTranslations(translations);
    const ariaLabel = closeButtonLabel ?? t.close;

    return (
      <div ref={ref} className={clsx(styles.header, className)} {...props}>
        <Heading
          slot="title"
          className={clsx(textClassNames["heading.lg"], styles.title)}
        >
          {children}
        </Heading>
        {showCloseButton && (
          <Button
            variant="ghost"
            color="neutral"
            size="sm"
            iconOnly
            iconStart={<XmarkIcon />}
            aria-label={ariaLabel}
            onClick={onClose}
          />
        )}
      </div>
    );
  }
);

ModalHeader.displayName = "Modal.Header";
