import { forwardRef, type HTMLAttributes } from "react";
import { clsx } from "clsx";
import * as styles from "./ModalBody.css";
import { useModalContext } from "../../ModalContext";

interface ModalBodyCustomProps {
  /**
   * When true, the body content takes the full width without horizontal padding.
   * @default false
   */
  fullWidth?: boolean;
}

export interface ModalBodyProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof ModalBodyCustomProps>,
    ModalBodyCustomProps {}

export const ModalBody = forwardRef<HTMLDivElement, ModalBodyProps>(
  ({ children, fullWidth = false, className, ...props }, forwardedRef) => {
    const { bodyRef } = useModalContext();

    return (
      <div
        ref={(node) => {
          // Handle forwarded ref
          if (typeof forwardedRef === "function") {
            forwardedRef(node);
          } else if (forwardedRef) {
            forwardedRef.current = node;
          }

          // Handle bodyRef from context (for draggable modals)
          if (bodyRef) bodyRef.current = node;
        }}
        className={clsx(styles.body({ fullWidth }), className)}
        {...props}
      >
        {children}
      </div>
    );
  }
);

ModalBody.displayName = "Modal.Body";
